{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Description": "Least-privilege Lambda execution role with permission boundaries",
  "Resources": {
    "LambdaExecutionRole": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "RoleName": "DataProcessorLambdaRole",
        "AssumeRolePolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Effect": "Allow",
              "Principal": {
                "Service": "lambda.amazonaws.com"
              },
              "Action": "sts:AssumeRole",
              "Condition": {
                "StringEquals": {
                  "sts:ExternalId": "unique-external-id-12345"
                }
              }
            }
          ]
        },
        "PermissionsBoundary": {
          "Fn::Sub": "arn:aws:iam::${AWS::AccountId}:policy/LambdaPermissionBoundary"
        },
        "ManagedPolicyArns": [
          "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
        ],
        "Policies": [
          {
            "PolicyName": "LeastPrivilegeS3Access",
            "PolicyDocument": {
              "Version": "2012-10-17",
              "Statement": [
                {
                  "Sid": "ReadSpecificBucket",
                  "Effect": "Allow",
                  "Action": [
                    "s3:GetObject",
                    "s3:ListBucket"
                  ],
                  "Resource": [
                    "arn:aws:s3:::my-input-bucket",
                    "arn:aws:s3:::my-input-bucket/*"
                  ],
                  "Condition": {
                    "StringLike": {
                      "s3:prefix": "data/*"
                    }
                  }
                },
                {
                  "Sid": "WriteSpecificBucket",
                  "Effect": "Allow",
                  "Action": [
                    "s3:PutObject"
                  ],
                  "Resource": "arn:aws:s3:::my-output-bucket/processed/*"
                },
                {
                  "Sid": "DenyDangerousActions",
                  "Effect": "Deny",
                  "Action": [
                    "iam:*",
                    "sts:AssumeRole",
                    "lambda:UpdateFunctionCode",
                    "lambda:UpdateFunctionConfiguration",
                    "lambda:CreateFunction"
                  ],
                  "Resource": "*"
                }
              ]
            }
          },
          {
            "PolicyName": "SecretsManagerAccess",
            "PolicyDocument": {
              "Version": "2012-10-17",
              "Statement": [
                {
                  "Effect": "Allow",
                  "Action": [
                    "secretsmanager:GetSecretValue"
                  ],
                  "Resource": "arn:aws:secretsmanager:us-east-1:123456789012:secret:prod/db/credentials-AbCdEf",
                  "Condition": {
                    "StringEquals": {
                      "secretsmanager:VersionStage": "AWSCURRENT"
                    }
                  }
                }
              ]
            }
          }
        ],
        "Tags": [
          {
            "Key": "Environment",
            "Value": "Production"
          },
          {
            "Key": "DataClassification",
            "Value": "Confidential"
          }
        ]
      }
    },
    "LambdaPermissionBoundary": {
      "Type": "AWS::IAM::ManagedPolicy",
      "Properties": {
        "ManagedPolicyName": "LambdaPermissionBoundary",
        "Description": "Maximum permissions boundary for Lambda execution roles",
        "PolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Sid": "AllowLambdaBasicExecution",
              "Effect": "Allow",
              "Action": [
                "logs:CreateLogGroup",
                "logs:CreateLogStream",
                "logs:PutLogEvents",
                "ec2:CreateNetworkInterface",
                "ec2:DescribeNetworkInterfaces",
                "ec2:DeleteNetworkInterface"
              ],
              "Resource": "*"
            },
            {
              "Sid": "AllowApplicationServices",
              "Effect": "Allow",
              "Action": [
                "s3:Get*",
                "s3:List*",
                "s3:PutObject",
                "dynamodb:GetItem",
                "dynamodb:PutItem",
                "dynamodb:Query",
                "secretsmanager:GetSecretValue"
              ],
              "Resource": "*"
            },
            {
              "Sid": "DenyPrivilegeEscalation",
              "Effect": "Deny",
              "Action": [
                "iam:*Policy*",
                "iam:*Role*",
                "iam:*User*",
                "iam:*Group*",
                "sts:AssumeRole",
                "lambda:UpdateFunctionCode*",
                "lambda:CreateFunction",
                "lambda:AddPermission"
              ],
              "Resource": "*"
            }
          ]
        }
      }
    }
  }
}

{
  "Version": "2012-10-17",
  "Id": "RestrictedInvocationPolicy",
  "Statement": [
    {
      "Sid": "AllowAPIGatewayInvoke",
      "Effect": "Allow",
      "Principal": {
        "Service": "apigateway.amazonaws.com"
      },
      "Action": "lambda:InvokeFunction",
      "Resource": "arn:aws:lambda:us-east-1:123456789012:function:MyFunction",
      "Condition": {
        "ArnLike": {
          "AWS:SourceArn": "arn:aws:execute-api:us-east-1:123456789012:abcdef123/*"
        }
      }
    },
    {
      "Sid": "AllowSpecificIAMRole",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::123456789012:role/TrustedApplicationRole"
      },
      "Action": "lambda:InvokeFunction",
      "Resource": "arn:aws:lambda:us-east-1:123456789012:function:MyFunction",
      "Condition": {
        "StringEquals": {
          "aws:SourceVpce": "vpce-12345678"
        },
        "IpAddress": {
          "aws:SourceIp": [
            "10.0.1.0/24",
            "10.0.2.0/24"
          ]
        }
      }
    },
    {
      "Sid": "DenyCrossAccountAccess",
      "Effect": "Deny",
      "Principal": "*",
      "Action": "lambda:InvokeFunction",
      "Resource": "arn:aws:lambda:us-east-1:123456789012:function:MyFunction",
      "Condition": {
        "StringNotEquals": {
          "aws:PrincipalAccount": "123456789012"
        }
      }
    },
    {
      "Sid": "DenyPublicInvocation",
      "Effect": "Deny",
      "Principal": "*",
      "Action": [
        "lambda:InvokeFunction",
        "lambda:InvokeFunctionUrl"
      ],
      "Resource": "arn:aws:lambda:us-east-1:123456789012:function:MyFunction",
      "Condition": {
        "StringNotEquals": {
          "aws:PrincipalOrgID": "o-abc12345"
        }
      }
    }
  ]
}

# Apply using AWS CLI
aws lambda add-permission \
  --function-name MyFunction \
  --statement-id AllowAPIGatewayInvoke \
  --action lambda:InvokeFunction \
  --principal apigateway.amazonaws.com \
  --source-arn "arn:aws:execute-api:us-east-1:123456789012:abcdef123/*"

# Terraform example
resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.my_function.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.my_api.execution_arn}/*"
}

resource "aws_lambda_permission" "deny_cross_account" {
  statement_id  = "DenyCrossAccountAccess"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.my_function.function_name
  principal     = "*"

  qualifier     = "$LATEST"

  # Use resource-based policy for complex conditions
  depends_on = [aws_lambda_function.my_function]
}

{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "RestrictPassRoleToLambda",
      "Effect": "Allow",
      "Action": "iam:PassRole",
      "Resource": "arn:aws:iam::*:role/LambdaExecution-*",
      "Condition": {
        "StringEquals": {
          "iam:PassedToService": "lambda.amazonaws.com"
        },
        "StringLike": {
          "iam:AssociatedResourceArn": [
            "arn:aws:lambda:us-east-1:123456789012:function:approved-*"
          ]
        },
        "ArnLike": {
          "iam:PolicyARN": [
            "arn:aws:iam::123456789012:policy/AllowedLambdaPolicy-*",
            "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
          ]
        }
      }
    },
    {
      "Sid": "DenyPassRoleToAdminRoles",
      "Effect": "Deny",
      "Action": "iam:PassRole",
      "Resource": [
        "arn:aws:iam::*:role/*Admin*",
        "arn:aws:iam::*:role/*Power*",
        "arn:aws:iam::*:role/OrganizationAccountAccessRole"
      ]
    },
    {
      "Sid": "DenyPassRoleWithDangerousPolicies",
      "Effect": "Deny",
      "Action": "iam:PassRole",
      "Resource": "*",
      "Condition": {
        "ArnLike": {
          "iam:PolicyARN": [
            "arn:aws:iam::aws:policy/AdministratorAccess",
            "arn:aws:iam::aws:policy/PowerUserAccess",
            "arn:aws:iam::aws:policy/IAMFullAccess"
          ]
        }
      }
    }
  ]
}

# AWS Organizations Service Control Policy (SCP)
# Apply to OUs to enforce account-level restrictions
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "DenyLambdaPrivilegeEscalation",
      "Effect": "Deny",
      "Action": [
        "lambda:UpdateFunctionConfiguration",
        "lambda:UpdateFunctionCode",
        "lambda:CreateFunction"
      ],
      "Resource": "*",
      "Condition": {
        "StringEquals": {
          "lambda:FunctionArn": [
            "arn:aws:lambda:*:*:function:production-*",
            "arn:aws:lambda:*:*:function:critical-*"
          ]
        },
        "StringNotEquals": {
          "aws:PrincipalOrgID": "o-abc12345",
          "aws:PrincipalAccount": "123456789012"
        }
      }
    },
    {
      "Sid": "RequirePermissionBoundaryForLambdaRoles",
      "Effect": "Deny",
      "Action": [
        "iam:CreateRole",
        "iam:PutRolePolicy",
        "iam:AttachRolePolicy"
      ],
      "Resource": "arn:aws:iam::*:role/LambdaExecution-*",
      "Condition": {
        "StringNotEquals": {
          "iam:PermissionsBoundary": "arn:aws:iam::123456789012:policy/LambdaPermissionBoundary"
        }
      }
    },
    {
      "Sid": "DenyDangerousLambdaActions",
      "Effect": "Deny",
      "Action": [
        "lambda:AddLayerVersionPermission",
        "lambda:AddPermission",
        "lambda:CreateEventSourceMapping",
        "lambda:PutFunctionConcurrency"
      ],
      "Resource": "*",
      "Condition": {
        "StringNotLike": {
          "aws:PrincipalArn": [
            "arn:aws:iam::*:role/SecOps-*",
            "arn:aws:iam::*:role/Admin-*"
          ]
        }
      }
    },
    {
      "Sid": "DenyLambdaInvokeWildcard",
      "Effect": "Deny",
      "Action": "lambda:InvokeFunction",
      "Resource": "*",
      "Condition": {
        "StringNotEquals": {
          "aws:RequestedRegion": [
            "us-east-1",
            "us-west-2"
          ]
        }
      }
    }
  ]
}

# Terraform example for PassRole restriction
resource "aws_iam_policy" "lambda_passrole_restriction" {
  name        = "LambdaPassRoleRestriction"
  description = "Restricts iam:PassRole for Lambda functions"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowPassRoleOnlyToLambda"
        Effect = "Allow"
        Action = "iam:PassRole"
        Resource = "arn:aws:iam::*:role/LambdaExecution-*"
        Condition = {
          StringEquals = {
            "iam:PassedToService" = "lambda.amazonaws.com"
          }
        }
      },
      {
        Sid      = "DenyPassAdminRoles"
        Effect   = "Deny"
        Action   = "iam:PassRole"
        Resource = "arn:aws:iam::*:role/*Admin*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach_passrole_restriction" {
  role       = aws_iam_role.developer_role.name
  policy_arn = aws_iam_policy.lambda_passrole_restriction.arn
}
